/* Translate a baked USA script ROM address to the active region's address.
 * Identity for USA, for unknown addresses, and in USA single-region builds. */
u32 Port_TranslateScriptAddr(u32 usa_addr) {
#if defined(MULTI_REGION) || defined(EU) || defined(JP)
    if (REGION_IS_USA)
        return usa_addr;
    {
        int lo = 0, hi = (int)SCRIPT_ADDR_COUNT - 1;
        while (lo <= hi) {
            int mid = (lo + hi) / 2;
            u32 k = sScriptAddrs[mid].usa;
            if (k == usa_addr)
                return REGION_IS_EU ? sScriptAddrs[mid].eu : sScriptAddrs[mid].jp;
            else if (k < usa_addr)
                lo = mid + 1;
            else
                hi = mid - 1;
        }
    }
#endif
    return usa_addr;
}
